import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [role, setRole] = useState(null); 
  const [students, setStudents] = useState([]);
  const [selectedFasal, setSelectedFasal] = useState("Dhamaan"); // Filter-ka fasalka
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    if (role === 'admin' || role === 'teacher') {
      axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
    }
  }, [role]);

  // KALA SAARISTA FASALADA (Filter Logic)
  const filteredStudents = students.filter(s => 
    selectedFasal === "Dhamaan" ? true : s.fasalka === selectedFasal
  );

  const TeacherAdminView = () => (
    <div style={{ padding: '20px' }}>
      <h2 style={{textAlign: 'center'}}>{role === 'admin' ? "💻 Maamulka (Admin)" : "👨‍🏫 Macallinka Fasalka"}</h2>

      {/* MEESHA FASALKA LAGU DOORTA (Option Bar) */}
      <div style={{ background: '#fff', padding: '15px', borderRadius: '10px', marginBottom: '20px', border: '2px solid #1a73e8' }}>
        <label style={{fontWeight: 'bold', marginRight: '10px'}}>Dooro Fasalka aad Xaadirinayso: </label>
        <select 
          style={{padding: '10px', borderRadius: '5px', width: '200px', cursor: 'pointer'}}
          onChange={(e) => setSelectedFasal(e.target.value)}
        >
          <option value="Dhamaan">Dhamaan Ardayda</option>
          <option value="Form 4">Form 4</option>
          <option value="Form 3">Form 3</option>
          <option value="Form 2">Form 2</option>
          <option value="Form 1">Form 1</option>
          <option value="Fasalka 1">Fasalka 1</option>
        </select>
        <span style={{marginLeft: '20px', color: '#666'}}>Ardayda la helay: <strong>{filteredStudents.length}</strong></span>
      </div>

      <table border="1" width="100%" style={{ borderCollapse: 'collapse', backgroundColor: 'white' }}>
        <thead style={{ background: '#2c3e50', color: '#fff' }}>
          <tr>
            <th style={{padding: '12px'}}>ID</th>
            <th>Magaca Ardayga</th>
            <th>Fasalka</th>
            {role === 'admin' && <th>Lacagta</th>}
            <th>Xaadiris</th>
          </tr>
        </thead>
        <tbody>
          {filteredStudents.map(s => (
            <tr key={s.id} style={{ textAlign: 'center' }}>
              <td style={{padding: '10px'}}>{s.id}</td>
              <td style={{fontWeight: 'bold'}}>{s.magaca}</td>
              <td><span style={{background: '#e8f0fe', padding: '4px 8px', borderRadius: '5px'}}>{s.fasalka}</span></td>
              {role === 'admin' && <td style={{color: s.lacagta === 'Bixiyey' ? 'green' : 'red'}}>{s.lacagta}</td>}
              <td>
                <button onClick={() => alert(`${s.magaca} (Fasalka ${s.fasalka}) waa la xaadiriyay!`)} style={{ backgroundColor: '#28a745', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '5px', cursor: 'pointer' }}>√ Sax</button>
                <button style={{ backgroundColor: '#dc3545', color: 'white', border: 'none', padding: '8px 12px', borderRadius: '5px', cursor: 'pointer', marginLeft: '5px' }}>X Maqan</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  // LOGOUT & LOGIN CODE (Sidee hore)
  if (!role) {
    return (
      <div style={{ textAlign: 'center', marginTop: '100px', fontFamily: 'Arial' }}>
        <h1>Dugsi Management System</h1>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginTop: '30px' }}>
          <button style={btnStyle} onClick={() => setRole('admin')}>Geli Admin</button>
          <button style={btnStyle} onClick={() => setRole('teacher')}>Geli Macallin</button>
          <button style={btnStyle} onClick={() => {
            const id = prompt("Geli ID-gaaga:");
            axios.post('http://localhost:3000/student/login', { id, password: "123" })
              .then(res => { setCurrentUser(res.data); setRole('student'); })
              .catch(() => alert("Aqoonsi khaldan!"));
          }}>Geli Arday</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ backgroundColor: '#f0f2f5', minHeight: '100vh', fontFamily: 'Arial' }}>
      <nav style={{background: '#2c3e50', padding: '10px', color: 'white', display: 'flex', justifyContent: 'space-between'}}>
         <span>Dugsi System</span>
         <button onClick={() => setRole(null)} style={{ backgroundColor: '#e74c3c', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '5px', cursor: 'pointer' }}>Logout</button>
      </nav>
      {role === 'student' ? <div style={{padding: '20px', textAlign: 'center'}}><h2>Natiijada: {currentUser?.dhibcaha}%</h2><p>Lacagta: {currentUser?.lacagta}</p></div> : <TeacherAdminView />}
    </div>
  );
}

const btnStyle = { padding: '20px', fontSize: '16px', cursor: 'pointer', borderRadius: '10px', border: 'none', background: '#1a73e8', color: 'white' };
export default App;
